$path = 'D:\이력서\ITT Cannon\Joonha_Lee_ITT_Cannon_FAE_Resume_Final_Integrated_v2.docx'
$word = New-Object -ComObject Word.Application
$word.Visible = $false
$results = @()
try {
    $doc = $word.Documents.Open($path, $false, $false)   # editable

    function Repl($doc, $old, $new) {
        foreach ($p in $doc.Paragraphs) {
            $rt = $p.Range.Text
            $idx = $rt.IndexOf($old)
            if ($idx -ge 0) {
                $sub = $doc.Range($p.Range.Start + $idx, $p.Range.Start + $idx + $old.Length)
                $sub.Text = $new
                return "OK"
            }
        }
        return "NOT FOUND"
    }

    # --- A) remove stray trailing backslash in Genohco heading ---
    $aRes = "Genohco para not found"
    foreach ($p in $doc.Paragraphs) {
        $rt = $p.Range.Text
        if ($rt -like 'Genohco `| Lead*') {
            $content = $rt.TrimEnd([char]13,[char]10)
            if ($content.EndsWith([char]92)) {
                $pos = $p.Range.Start + $content.Length - 1
                $sub = $doc.Range($pos, $pos + 1)
                $sub.Text = ''
                $aRes = "OK backslash removed"
            } else {
                $aRes = "no backslash; last char code=" + [int]($content[$content.Length-1])
            }
            break
        }
    }
    $results += "A backslash: $aRes"

    # --- B) double period fix ---
    $results += "B doubleperiod: " + (Repl $doc 'production quality issues..' 'production quality issues.')

    # --- C) 15 -> 14 years ---
    $results += "C years: " + (Repl $doc 'approximately 15 years and 11 months' 'approximately 14 years and 11 months')

    # --- D) add period to WBS bullet ---
    $dRes = "WBS para not found"
    foreach ($p in $doc.Paragraphs) {
        $rt = $p.Range.Text
        if ($rt -like '*Managed WBS-based schedules*') {
            $idx = $rt.IndexOf('customer acceptance')
            if ($idx -ge 0) {
                $sub = $doc.Range($p.Range.Start + $idx, $p.Range.Start + $idx + 'customer acceptance'.Length)
                $sub.Text = 'customer acceptance.'
                $dRes = "OK period added"
            } else { $dRes = "phrase not found in para" }
            break
        }
    }
    $results += "D wbsperiod: $dRes"

    # --- E) materials strength: ground in Daeyang mechanical design + outsourced fabrication ---
    $eOld = 'EMC/RoHS and the use of high-performance thermoplastics, aluminum and copper alloys and their production requirements.'
    $eNew = 'EMC/RoHS. At Daeyang Electric I also handled mechanical/enclosure design and outsourced fabrication of equipment housings and parts, giving hands-on insight into high-performance thermoplastics, aluminum and copper alloys and the manufacturing requirements needed to utilize them.'
    $results += "E materials: " + (Repl $doc $eOld $eNew)

    # --- F) insert new Transportation/Rail Key Strength bullet after para 33 ---
    $txtF = 'Transportation & Industrial Market Relevance (Rail): At Daeyang Electric I also worked on railway-vehicle (rolling-stock) PCB and cable design, giving direct relevance to ITT Cannon''s Transportation & Industrial markets (Rail, Heavy Vehicles, Energy) and to harsh-environment, high-vibration interconnect and cabling requirements.'
    $leadF = 'Transportation & Industrial Market Relevance (Rail):'
    $p33 = $doc.Paragraphs.Item(33)
    if ($p33.Range.Text -like 'Aerospace & Defense / Military*') {
        $p33.Range.InsertParagraphAfter()
        $newP = $p33.Next()
        $newP.Style = $doc.Styles.Item('글머리 기호')
        $ins = $newP.Range
        $ins.Collapse(1)
        $ins.InsertBefore($txtF)
        $body = $doc.Range($ins.Start, $ins.Start + $txtF.Length)
        $body.Font.Bold = [int]0
        $lead = $doc.Range($ins.Start, $ins.Start + $leadF.Length)
        $lead.Font.Bold = [int]1
        $results += "F transport bullet: OK"
    } else {
        $results += "F transport bullet: anchor mismatch -> " + (($p33.Range.Text) -replace "[\r\n]","").Substring(0,40)
    }

    # --- G) insert Daeyang substantiation responsibility bullet after VHF bullet ---
    $txtG = 'Also handled railway-vehicle (rolling-stock) PCB and cable design, plus mechanical/enclosure design and outsourced fabrication of equipment housings and parts using high-performance thermoplastics, aluminum and copper alloys and the manufacturing requirements needed to utilize them.'
    $gRes = "VHF para not found"
    foreach ($p in $doc.Paragraphs) {
        $t = ($p.Range.Text -replace "[\r\n\a\x07]","").Trim()
        if ($t -like 'Verified VHF/UHF/HF*') {
            $p.Range.InsertParagraphAfter()
            $newG = $p.Next()
            $newG.Style = $doc.Styles.Item('글머리 기호')
            $insG = $newG.Range
            $insG.Collapse(1)
            $insG.InsertBefore($txtG)
            $bodyG = $doc.Range($insG.Start, $insG.Start + $txtG.Length)
            $bodyG.Font.Bold = [int]0
            $gRes = "OK"
            break
        }
    }
    $results += "G daeyang bullet: $gRes"

    $doc.Save()
    $results += "SAVED"
    $results -join "`n"
} finally {
    if ($doc) { $doc.Close([ref]$true) }
    if ($word.Documents.Count -eq 0) { $word.Quit() }
}

